// src/core/Camera.ts
var DEFAULT_CONFIG = {
  scrollSpeed: 500,
  edgeMargin: 20,
  worldWidth: 3200,
  worldHeight: 3200
};

class Camera {
  x = 0;
  y = 0;
  viewportWidth = 0;
  viewportHeight = 0;
  uiBottomMargin = 0;
  config;
  keys = new Set;
  mouseX = 0;
  mouseY = 0;
  mouseInWindow = false;
  isPanningTouch = false;
  touchStartX = 0;
  touchStartY = 0;
  boundKeyDown;
  boundKeyUp;
  boundMouseMove;
  boundMouseEnter;
  boundMouseLeave;
  boundTouchStart;
  boundTouchMove;
  boundTouchEnd;
  constructor(config) {
    this.config = { ...DEFAULT_CONFIG, ...config };
    this.boundKeyDown = (e) => this.onKeyDown(e);
    this.boundKeyUp = (e) => this.onKeyUp(e);
    this.boundMouseMove = (e) => this.onMouseMove(e);
    this.boundMouseEnter = () => {
      this.mouseInWindow = true;
    };
    this.boundMouseLeave = () => {
      this.mouseInWindow = false;
    };
    this.boundTouchStart = (e) => this.onTouchStart(e);
    this.boundTouchMove = (e) => this.onTouchMove(e);
    this.boundTouchEnd = (e) => this.onTouchEnd(e);
    window.addEventListener("keydown", this.boundKeyDown);
    window.addEventListener("keyup", this.boundKeyUp);
    window.addEventListener("mousemove", this.boundMouseMove);
    window.addEventListener("mouseenter", this.boundMouseEnter);
    window.addEventListener("mouseleave", this.boundMouseLeave);
    window.addEventListener("touchstart", this.boundTouchStart, { passive: false });
    window.addEventListener("touchmove", this.boundTouchMove, { passive: false });
    window.addEventListener("touchend", this.boundTouchEnd);
    window.addEventListener("touchcancel", this.boundTouchEnd);
  }
  resize(width, height) {
    this.viewportWidth = width;
    this.viewportHeight = height;
  }
  update(dt) {
    const speed = this.config.scrollSpeed * dt;
    let dx = 0;
    let dy = 0;
    if (this.keys.has("ArrowLeft") || this.keys.has("a"))
      dx -= 1;
    if (this.keys.has("ArrowRight") || this.keys.has("d"))
      dx += 1;
    if (this.keys.has("ArrowUp") || this.keys.has("w"))
      dy -= 1;
    if (this.keys.has("ArrowDown") || this.keys.has("s"))
      dy += 1;
    if (this.mouseInWindow) {
      const margin = this.config.edgeMargin;
      if (this.mouseX <= margin)
        dx -= 1;
      if (this.mouseX >= this.viewportWidth - margin)
        dx += 1;
      if (this.mouseY <= margin)
        dy -= 1;
      if (this.mouseY >= this.viewportHeight - margin)
        dy += 1;
    }
    if (dx !== 0 && dy !== 0) {
      const inv = 1 / Math.SQRT2;
      dx *= inv;
      dy *= inv;
    }
    this.x += dx * speed;
    this.y += dy * speed;
    this.clamp();
  }
  clamp() {
    const maxX = this.config.worldWidth - this.viewportWidth;
    const maxY = this.config.worldHeight - (this.viewportHeight - this.uiBottomMargin);
    this.x = Math.max(0, Math.min(this.x, maxX));
    this.y = Math.max(0, Math.min(this.y, maxY));
  }
  applyTransform(ctx) {
    ctx.setTransform(1, 0, 0, 1, -Math.round(this.x), -Math.round(this.y));
  }
  resetTransform(ctx) {
    ctx.setTransform(1, 0, 0, 1, 0, 0);
  }
  screenToWorld(sx, sy) {
    return { x: sx + this.x, y: sy + this.y };
  }
  worldToScreen(wx, wy) {
    return { x: wx - this.x, y: wy - this.y };
  }
  centerOn(wx, wy) {
    this.x = wx - this.viewportWidth / 2;
    this.y = wy - this.viewportHeight / 2;
    this.clamp();
  }
  setWorldSize(w, h) {
    this.config.worldWidth = w;
    this.config.worldHeight = h;
    this.clamp();
  }
  setBottomMargin(margin) {
    this.uiBottomMargin = margin;
    this.clamp();
  }
  destroy() {
    window.removeEventListener("keydown", this.boundKeyDown);
    window.removeEventListener("keyup", this.boundKeyUp);
    window.removeEventListener("mousemove", this.boundMouseMove);
    window.removeEventListener("mouseenter", this.boundMouseEnter);
    window.removeEventListener("mouseleave", this.boundMouseLeave);
    window.removeEventListener("touchstart", this.boundTouchStart);
    window.removeEventListener("touchmove", this.boundTouchMove);
    window.removeEventListener("touchend", this.boundTouchEnd);
    window.removeEventListener("touchcancel", this.boundTouchEnd);
  }
  onKeyDown(e) {
    this.keys.add(e.key);
  }
  onKeyUp(e) {
    this.keys.delete(e.key);
  }
  onMouseMove(e) {
    this.mouseX = e.clientX;
    this.mouseY = e.clientY;
    this.mouseInWindow = true;
  }
  onTouchStart(e) {
    if (e.touches.length >= 2) {
      this.isPanningTouch = true;
      this.touchStartX = (e.touches[0].clientX + e.touches[1].clientX) / 2;
      this.touchStartY = (e.touches[0].clientY + e.touches[1].clientY) / 2;
    }
  }
  onTouchMove(e) {
    if (this.isPanningTouch && e.touches.length >= 2) {
      const mx = (e.touches[0].clientX + e.touches[1].clientX) / 2;
      const my = (e.touches[0].clientY + e.touches[1].clientY) / 2;
      const dx = mx - this.touchStartX;
      const dy = my - this.touchStartY;
      this.x -= dx;
      this.y -= dy;
      this.touchStartX = mx;
      this.touchStartY = my;
      this.clamp();
    }
  }
  onTouchEnd(e) {
    if (e.touches.length < 2) {
      this.isPanningTouch = false;
    }
  }
}

// src/core/GameLoop.ts
class GameLoop {
  callbacks;
  lastTimestamp = 0;
  rafId = 0;
  running = false;
  maxDt = 1 / 15;
  frameCount = 0;
  fpsAccumulator = 0;
  fps = 0;
  lastRenderTimeMs = 0;
  renderMetrics = { terrain: 0, entities: 0, particles: 0, fog: 0, ui: 0 };
  constructor(callbacks) {
    this.callbacks = callbacks;
  }
  start() {
    if (this.running)
      return;
    this.running = true;
    this.lastTimestamp = performance.now();
    this.rafId = requestAnimationFrame((ts) => this.tick(ts));
  }
  stop() {
    this.running = false;
    if (this.rafId) {
      cancelAnimationFrame(this.rafId);
      this.rafId = 0;
    }
  }
  tick(timestamp) {
    if (!this.running)
      return;
    let dt = (timestamp - this.lastTimestamp) / 1000;
    this.lastTimestamp = timestamp;
    if (dt > this.maxDt)
      dt = this.maxDt;
    this.frameCount++;
    this.fpsAccumulator += dt;
    if (this.fpsAccumulator >= 1) {
      this.fps = this.frameCount;
      this.frameCount = 0;
      this.fpsAccumulator -= 1;
    }
    this.callbacks.update(dt);
    this.callbacks.render(dt);
    this.rafId = requestAnimationFrame((ts) => this.tick(ts));
  }
}

