      const nx = c / cols, ny = r / rows;
      const biome = noise2d(nx * 4, ny * 4, rng);
      const detail = noise2d(nx * 10 + 3, ny * 10 + 3, rng);
      const fine = noise2d(nx * 20 + 7, ny * 20 + 7, rng);
