      const biome = noise2d(nx * 5, ny * 5, rng);
      const detail = noise2d(nx * 12 + 2, ny * 12 + 2, rng);
      const fine = noise2d(nx * 25 + 8, ny * 25 + 8, rng);
      let tile;
