      rightArmRot = -Math.PI / 4 * (1 - t) + 0.2 * t;
      leftArmRot = Math.PI / 10 * (1 - t) + 0 * t;
      bodyTilt = 0.15 * (1 - t) + 0 * t;
      swordOffsetX = 5 * (1 - t);
