  ctx.rotate(Math.PI / 10);
  ctx.fillStyle = "#ffd700";
  ctx.beginPath();
  ctx.arc(0, 6, 1.5, 0, Math.PI * 2);
  ctx.fill();
  ctx.fillStyle = "#222";
  ctx.fillRect(-1, 0, 2, 6);
  ctx.fillStyle = armorPrimary;
  ctx.beginPath();
  ctx.moveTo(0, 0);
  ctx.lineTo(-3, -1);
  ctx.lineTo(-4, -2);
  ctx.lineTo(-1, 1);
  ctx.fill();
  ctx.beginPath();
  ctx.moveTo(0, 0);
  ctx.lineTo(3, -1);
  ctx.lineTo(4, -2);
  ctx.lineTo(1, 1);
  ctx.fill();
  ctx.fillStyle = age >= 4 ? "#f0f0f0" : "#cccccc";
  ctx.beginPath();
  ctx.moveTo(-1, 0);
  ctx.lineTo(-1, -10);
  ctx.quadraticCurveTo(-2, -20, 5, -28);
  ctx.lineTo(3, -27);
  ctx.quadraticCurveTo(2, -15, 1, 0);
  ctx.fill();
  if (age >= 4) {
    ctx.strokeStyle = "#rgba(0,0,0,0.1)";
    ctx.lineWidth = 0.5;
    for (let i = 0;i < 3; i++) {
      ctx.beginPath();
      ctx.moveTo(0, -2 - i * 5);
      ctx.quadraticCurveTo(0, -10 - i * 5, 3, -15 - i * 5);
      ctx.stroke();
    }
  }
  if (attackState && attackProgress >= 0.3 && attackProgress < 0.6) {
    ctx.fillStyle = "rgba(255, 255, 255, 0.5)";
    ctx.beginPath();
    ctx.moveTo(3, -10);
    ctx.quadraticCurveTo(20, -10, 10, -28);
    ctx.lineTo(5, -28);
    ctx.quadraticCurveTo(15, -15, 0, 0);
    ctx.fill();
  }
  ctx.restore();
  ctx.fillStyle = tunicColor;
