    ctx.moveTo(stringMidX + arrowLen, -1.5);
    ctx.lineTo(stringMidX + arrowLen + 3, 0);
    ctx.lineTo(stringMidX + arrowLen, 1.5);
    ctx.fill();
    ctx.fillStyle = armorMetal;
    ctx.fillRect(stringMidX, -1.5, 3, 3);
    ctx.restore();
