      leftArmRot = Math.PI / 12 * (1 - t) + 0 * t;
      bodyTilt = 0.2 * (1 - t) + 0 * t;
      swordOffsetX = 6 * (1 - t);
      swordOffsetY = 3 * (1 - t);
