  ctx.fillStyle = "#e0e0e0";
  ctx.beginPath();
  ctx.moveTo(-1, 2.5);
  ctx.lineTo(-1, 14);
  ctx.quadraticCurveTo(0, 18, 2, 16);
  ctx.lineTo(1.5, 2.5);
  ctx.fill();
  ctx.fillStyle = "#fff";
  ctx.fillRect(0.5, 3, 1, 12);
