  ctx.beginPath();
  ctx.moveTo(-6.5, -6 + walkBob);
  ctx.lineTo(-1, -6 + walkBob);
  ctx.lineTo(-2, 5 + walkBob);
  ctx.lineTo(-5.5, 7 + walkBob);
