function getCivHeroVisuals(unit) {
  const civ = unit.civilization;
  const t = unit.type;
  let result;
  if (civ === "baTu" /* BaTu */) {
    if (t === "heroZarathustra" /* HeroZarathustra */)
      result = { color: "#ff4400", symbol: "\uD83D\uDD25" };
    else
      result = { color: "#ff4400", symbol: "\uD83D\uDD25" };
  } else if (civ === "daiTong" /* DaiMinh */) {
    if (t === "heroHuangZhong" /* HeroQiJiguang */)
      result = { color: "#ff9800", symbol: "\uD83C\uDFF9" };
    else
      result = { color: "#ff9800", symbol: "\uD83C\uDFF9" };
  } else if (civ === "yamato" /* Yamato */) {
    if (t === "heroMusashi" /* HeroMusashi */)
      result = { color: "#607d8b", symbol: "⚔" };
    else
      result = { color: "#607d8b", symbol: "⚔" };
  } else if (civ === "laMa" /* LaMa */) {
    if (t === "heroSpartacus" /* HeroSpartacus */)
      result = { color: "#c62828", symbol: "\uD83D\uDDE1" };
    else
      result = { color: "#c62828", symbol: "\uD83D\uDDE1" };
  } else if (civ === "viking" /* Viking */) {
    if (t === "heroRagnar" /* HeroRagnar */)
      result = { color: "#795548", symbol: "⚔" };
    else
      result = { color: "#795548", symbol: "⚔" };
  } else {
    result = { color: "#ff4444", symbol: "⚔" };
  }
  if (unit.slotColor)
    result.color = unit.slotColor;
  return result;
}
