        const megaSlash = swingCycle * 1.5 - 0.3;
        ctx.translate(8, -6 + totalBob);
        ctx.rotate(megaSlash);
        ctx.fillStyle = "#ddd";
        ctx.fillRect(-2, -22, 4, 20);
        ctx.fillStyle = "#ffd700";
        ctx.fillRect(-5, -3, 10, 3);
        ctx.fillStyle = "#5a2a0a";
        ctx.fillRect(-1, 0, 3, 5);
        ctx.globalAlpha = 0.3;
        ctx.strokeStyle = "#ff6644";
        ctx.lineWidth = 3;
        ctx.beginPath();
        ctx.arc(0, -10, 20, megaSlash - 1, megaSlash + 0.3);
