          ctx.strokeStyle = "#dd3333";
          ctx.lineWidth = 3;
          ctx.beginPath();
          ctx.arc(0, -6 + totalBob, 18, arcStart - 0.7, arcStart + 0.3);
          ctx.stroke();
          ctx.strokeStyle = "#ffcccc";
          ctx.lineWidth = 1.5;
