        ctx.strokeStyle = "#ffffee";
        ctx.lineWidth = 2;
        ctx.beginPath();
        ctx.moveTo(0, -6 + totalBob);
        ctx.lineTo(thrustAmt * 18, -6 + totalBob);
        ctx.stroke();
