                e.hp -= 8;
                t++;
                particles.emit({ x: e.x, y: e.y - 4, count: 6, spread: 4, speed: [20, 60], angle: [-Math.PI * 0.8, -Math.PI * 0.2], life: [0.2, 0.5], size: [2, 4], colors: ["#ff4400", "#ff6600", "#ffaa00"], gravity: -40, shape: "circle" });
