        particles.emit({ x: unit.x, y: unit.y - 10, count: 16, spread: 8, speed: [20, 60], angle: [-Math.PI * 0.9, -Math.PI * 0.1], life: [0.8, 1.8], size: [3, 5], colors: ["#ffd700", "#ffee8888"], gravity: -40, shape: "star" });
