          particles.emit({ x: unit.x + Math.cos(a) * r, y: unit.y + Math.sin(a) * r * 0.6, count: 5, spread: 3, speed: [15, 40], angle: [a + Math.PI * 0.4, a + Math.PI * 0.6], life: [0.8, 1.5], size: [3, 6], colors: ["#9c27b0", "#ce93d8", "#e1bee7", "#fff"], gravity: -5, shape: "star" });
