        particles.emit({ x: unit.x, y: unit.y, count: 16, spread: 30, speed: [10, 30], angle: [0, Math.PI * 2], life: [1, 2.5], size: [6, 14], colors: ["#9c27b044", "#4caf5044", "#e1bee733"], gravity: 0, shape: "circle" });
