      newX += pushX / pushLen * pushScale;
      newY += pushY / pushLen * pushScale;
      const [pushCol, pushRow] = tileMap.worldToTile(newX, newY);
      if (!tileMap.isWalkable(pushCol, pushRow)) {
        newX -= pushX / pushLen * pushScale;
        newY -= pushY / pushLen * pushScale;
      }
