    ctx.lineWidth = 2;
    ctx.beginPath();
    ctx.moveTo(left + 8, top + 8);
    ctx.quadraticCurveTo(left, top - 5, left + 4, top - 8);
    ctx.stroke();
    ctx.beginPath();
    ctx.moveTo(left + w - 8, top + 8);
    ctx.quadraticCurveTo(left + w, top - 5, left + w - 4, top - 8);
    ctx.stroke();
