          count: 3,
          spread: 2,
          speed: [200, 260],
          angle: [spreadAngle - 0.1, spreadAngle + 0.1],
          life: [0.1, 0.25],
          size: [2, 3],
          colors: ["#ff4400", "#ff8800", "#ffcc00"],
          gravity: 20,
          shape: "circle"
