      x: target.x,
      y: target.y - 5,
      count: this.age >= 4 ? 6 : 4,
      spread: 5,
      speed: [30, 80],
      angle: [angle - 0.5, angle + 0.5],
      life: [0.15, 0.35],
      size: [1.5, 3],
