// src/systems/EntityManager.ts
var GRID_CELL_SIZE = TILE_SIZE * 8;
var GRID_COLS = Math.ceil(MAP_COLS * TILE_SIZE / GRID_CELL_SIZE);
var GRID_ROWS = Math.ceil(MAP_ROWS * TILE_SIZE / GRID_CELL_SIZE);

class SpatialGrid {
  cells = [];
  constructor() {
    for (let i = 0;i < GRID_COLS * GRID_ROWS; i++) {
      this.cells.push([]);
    }
  }
  clear() {
    for (const cell of this.cells)
      cell.length = 0;
  }
  insert(u) {
    const cx = Math.floor(u.x / GRID_CELL_SIZE);
    const cy = Math.floor(u.y / GRID_CELL_SIZE);
    if (cx < 0 || cx >= GRID_COLS || cy < 0 || cy >= GRID_ROWS)
      return;
    this.cells[cy * GRID_COLS + cx].push(u);
  }
  getNearby(x, y) {
    const cx = Math.floor(x / GRID_CELL_SIZE);
    const cy = Math.floor(y / GRID_CELL_SIZE);
    const result = [];
    for (let dy = -1;dy <= 1; dy++) {
      for (let dx = -1;dx <= 1; dx++) {
        const nx = cx + dx, ny = cy + dy;
        if (nx < 0 || nx >= GRID_COLS || ny < 0 || ny >= GRID_ROWS)
          continue;
        const cell = this.cells[ny * GRID_COLS + nx];
        for (let i = 0;i < cell.length; i++)
          result.push(cell[i]);
      }
    }
    return result;
  }
  getInRange(x, y, range) {
    const cellRange = Math.ceil(range / GRID_CELL_SIZE) + 1;
    const cx = Math.floor(x / GRID_CELL_SIZE);
    const cy = Math.floor(y / GRID_CELL_SIZE);
    const result = [];
    const rangeSq = range * range;
    for (let dy = -cellRange;dy <= cellRange; dy++) {
      for (let dx = -cellRange;dx <= cellRange; dx++) {
        const nx = cx + dx, ny = cy + dy;
        if (nx < 0 || nx >= GRID_COLS || ny < 0 || ny >= GRID_ROWS)
          continue;
        const cell = this.cells[ny * GRID_COLS + nx];
        for (let i = 0;i < cell.length; i++) {
          const u = cell[i];
          const ddx = u.x - x, ddy = u.y - y;
          if (ddx * ddx + ddy * ddy <= rangeSq)
            result.push(u);
        }
      }
    }
    return result;
  }
}

